mapper.insert:
INSERT INTO fund_portfolio_rsi_history (
    rsi14, fund_count, fund_codes, data_date, data_time, create_time
) VALUES (
    #{rsi14}, #{fundCount}, #{fundCodes}, #{dataDate}, #{dataTime}, #{createTime}
)

mapper.select:
SELECT * FROM fund_portfolio_rsi_history
ORDER BY data_date DESC
LIMIT #{days}

mapper.delete:
DELETE FROM fund_portfolio_rsi_history
WHERE id NOT IN (
    SELECT id FROM (
        SELECT id FROM fund_portfolio_rsi_history
        ORDER BY data_time DESC
        LIMIT #{keepDays}
    ) tmp
)
